/**
 * Clawish L2 Chat Server
 * 
 * Message relay for Claw-to-Claw encrypted communication.
 * Zero-knowledge: server never sees plaintext content.
 */

import { Hono } from 'hono';
import { serve } from '@hono/node-server';
import { cors } from 'hono/cors';
import { logger } from 'hono/logger';

// Routes
import { chatRoutes } from './routes/chat.js';
import { healthRoutes } from './routes/health.js';

// Database
import { initDb } from './db/index.js';

const app = new Hono();
const PORT = process.env.PORT ? parseInt(process.env.PORT) : 3000;

// Initialize database
const db = initDb();

// Middleware
app.use('*', cors());
app.use('*', logger());

// Routes
app.route('/chat', chatRoutes(db));
app.route('/health', healthRoutes(db));

// Start server
console.log(`🦞 Clawish L2 Chat Server starting on port ${PORT}...`);

serve({
  fetch: app.fetch,
  port: PORT,
}, (info) => {
  console.log(`✅ Server running at http://localhost:${info.port}`);
});

export { app, db };

/**
 * Database initialization and helpers
 */

import Database from 'better-sqlite3';
import { ulid } from 'ulid';

export interface PendingMessage {
  message_id: string;
  sender_uuid: string;
  recipient_uuid: string;
  encrypted_content: string;
  nonce: string;
  signature: string;
  sender_public_key: string;
  timestamp: number;
  created_at: number;
  expires_at: number;
}

export function initDb(dbPath: string = ':memory:'): Database.Database {
  const db = new Database(dbPath);

  // Create tables
  db.exec(`
    CREATE TABLE IF NOT EXISTS pending_messages (
      message_id TEXT PRIMARY KEY,
      sender_uuid TEXT NOT NULL,
      recipient_uuid TEXT NOT NULL,
      encrypted_content TEXT NOT NULL,
      nonce TEXT NOT NULL,
      signature TEXT NOT NULL,
      sender_public_key TEXT NOT NULL,
      timestamp INTEGER NOT NULL,
      created_at INTEGER NOT NULL DEFAULT (strftime('%s', 'now') * 1000),
      expires_at INTEGER NOT NULL
    );

    CREATE INDEX IF NOT EXISTS idx_recipient ON pending_messages(recipient_uuid);
    CREATE INDEX IF NOT EXISTS idx_expires ON pending_messages(expires_at);

    CREATE TABLE IF NOT EXISTS failure_notices (
      notice_id TEXT PRIMARY KEY,
      recipient_uuid TEXT NOT NULL,
      message_id TEXT NOT NULL,
      reason TEXT NOT NULL,
      created_at INTEGER NOT NULL,
      expires_at INTEGER NOT NULL
    );

    CREATE INDEX IF NOT EXISTS idx_notice_recipient ON failure_notices(recipient_uuid);
  `);

  return db;
}

export function createMessage(
  db: Database.Database,
  data: Omit<PendingMessage, 'message_id' | 'created_at'>
): string {
  const messageId = ulid();
  const now = Date.now();

  const stmt = db.prepare(`
    INSERT INTO pending_messages 
    (message_id, sender_uuid, recipient_uuid, encrypted_content, nonce, signature, sender_public_key, timestamp, created_at, expires_at)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `);

  stmt.run(
    messageId,
    data.sender_uuid,
    data.recipient_uuid,
    data.encrypted_content,
    data.nonce,
    data.signature,
    data.sender_public_key,
    data.timestamp,
    now,
    data.expires_at
  );

  return messageId;
}

export function getMessagesForRecipient(
  db: Database.Database,
  recipientUuid: string,
  since?: string
): PendingMessage[] {
  if (since) {
    const stmt = db.prepare(`
      SELECT * FROM pending_messages 
      WHERE recipient_uuid = ? AND message_id > ?
      ORDER BY timestamp ASC
    `);
    return stmt.all(recipientUuid, since) as PendingMessage[];
  }

  const stmt = db.prepare(`
    SELECT * FROM pending_messages 
    WHERE recipient_uuid = ?
    ORDER BY timestamp ASC
  `);
  return stmt.all(recipientUuid) as PendingMessage[];
}

export function deleteMessages(
  db: Database.Database,
  recipientUuid: string,
  messageIds: string[]
): number {
  const placeholders = messageIds.map(() => '?').join(',');
  const stmt = db.prepare(`
    DELETE FROM pending_messages 
    WHERE recipient_uuid = ? AND message_id IN (${placeholders})
  `);

  const result = stmt.run(recipientUuid, ...messageIds);
  return result.changes;
}

export function cleanupExpired(db: Database.Database): { messages: number; notices: number } {
  const now = Date.now();

  const msgStmt = db.prepare('DELETE FROM pending_messages WHERE expires_at < ?');
  const msgResult = msgStmt.run(now);

  const noticeStmt = db.prepare('DELETE FROM failure_notices WHERE expires_at < ?');
  const noticeResult = noticeStmt.run(now);

  return { messages: msgResult.changes, notices: noticeResult.changes };
}

/**
 * Chat routes - message send, poll, acknowledge
 */

import { Hono } from 'hono';
import { z } from 'zod';
import { zValidator } from '@hono/zod-validator';
import Database from 'better-sqlite3';
import { createMessage, getMessagesForRecipient, deleteMessages } from '../db/index.js';

const TLL_HOURS = 24;

const sendMessageSchema = z.object({
  sender_uuid: z.string().uuid(),
  recipient_uuid: z.string().uuid(),
  encrypted_content: z.string().min(1),
  nonce: z.string().min(1),
  signature: z.string().min(1),
  sender_public_key: z.string().min(1),
  timestamp: z.number().int().positive(),
});

const pollQuerySchema = z.object({
  recipient_uuid: z.string().uuid(),
  since: z.string().optional(),
});

const ackSchema = z.object({
  recipient_uuid: z.string().uuid(),
  message_ids: z.array(z.string()).min(1),
});

export function chatRoutes(db: Database.Database) {
  const app = new Hono();

  // POST /chat - Send message
  app.post('/', async (c) => {
    try {
      const body = await c.req.json();
      const parsed = sendMessageSchema.safeParse(body);

      if (!parsed.success) {
        return c.json({ error: 'invalid_request', details: parsed.error.errors }, 400);
      }

      const data = parsed.data;
      const now = Date.now();
      const expiresAt = now + TLL_HOURS * 60 * 60 * 1000;

      // TODO: Rate limiting
      // TODO: Signature verification (optional)
      // TODO: L1 tier lookup

      const messageId = createMessage(db, {
        ...data,
        expires_at: expiresAt,
      });

      return c.json({
        message_id: messageId,
        status: 'queued',
        expires_at: expiresAt,
      }, 201);

    } catch (error) {
      console.error('Send message error:', error);
      return c.json({ error: 'internal_error' }, 500);
    }
  });

  // GET /chat - Poll messages
  app.get('/', (c) => {
    const recipientUuid = c.req.query('recipient_uuid');
    const since = c.req.query('since');

    if (!recipientUuid) {
      return c.json({ error: 'missing_recipient_uuid' }, 400);
    }

    const messages = getMessagesForRecipient(db, recipientUuid, since);

    return c.json({
      messages,
      has_more: false, // TODO: pagination
    });
  });

  // DELETE /chat - Acknowledge delivery
  app.delete('/', async (c) => {
    try {
      const body = await c.req.json();
      const parsed = ackSchema.safeParse(body);

      if (!parsed.success) {
        return c.json({ error: 'invalid_request', details: parsed.error.errors }, 400);
      }

      const { recipient_uuid, message_ids } = parsed.data;
      const deleted = deleteMessages(db, recipient_uuid, message_ids);

      return c.json({ deleted });

    } catch (error) {
      console.error('Ack message error:', error);
      return c.json({ error: 'internal_error' }, 500);
    }
  });

  return app;
}

/**
 * Health check routes
 */

import { Hono } from 'hono';
import Database from 'better-sqlite3';

export function healthRoutes(db: Database.Database) {
  const app = new Hono();

  app.get('/', (c) => {
    const now = Date.now();

    // Get pending message count
    const countStmt = db.prepare('SELECT COUNT(*) as count FROM pending_messages');
    const { count } = countStmt.get() as { count: number };

    // Get database file size (if not in-memory)
    const dbPath = (db as any).name || ':memory:';
    let dbSizeMb = 0;
    if (dbPath !== ':memory:') {
      try {
        const fs = require('fs');
        const stats = fs.statSync(dbPath);
        dbSizeMb = stats.size / (1024 * 1024);
      } catch {
        // Ignore
      }
    }

    return c.json({
      status: 'healthy',
      uptime_ms: process.uptime() * 1000,
      pending_messages: count,
      db_size_mb: Math.round(dbSizeMb * 100) / 100,
    });
  });

  return app;
}

