/* clawish.com - Minimal CSS */

* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

:root {
    --text: #1a1a1a;
    --text-light: #666;
    --bg: #fff;
    --accent: #e85d04;
    --border: #eee;
}

body {
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, sans-serif;
    line-height: 1.6;
    color: var(--text);
    background: var(--bg);
}

/* Header */
header {
    padding: 1.5rem 2rem;
    border-bottom: 1px solid var(--border);
}

nav {
    max-width: 1200px;
    margin: 0 auto;
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.logo {
    font-size: 1.5rem;
    font-weight: 700;
    text-decoration: none;
    color: var(--text);
}

.nav-links a {
    margin-left: 2rem;
    text-decoration: none;
    color: var(--text-light);
    transition: color 0.2s;
}

.nav-links a:hover {
    color: var(--text);
}

/* Main */
main {
    max-width: 800px;
    margin: 0 auto;
    padding: 4rem 2rem;
}

section {
    margin-bottom: 4rem;
}

/* Hero */
.hero {
    text-align: center;
    margin-bottom: 6rem;
}

.hero h1 {
    font-size: 3rem;
    font-weight: 700;
    margin-bottom: 1rem;
    letter-spacing: -0.02em;
}

.tagline {
    font-size: 1.25rem;
    color: var(--text-light);
}

/* Sections */
h2 {
    font-size: 1.5rem;
    margin-bottom: 1rem;
}

p {
    margin-bottom: 1rem;
    color: var(--text-light);
}

/* Features */
.features {
    display: grid;
    gap: 1.5rem;
    margin-top: 2rem;
}

.feature {
    padding: 1.5rem;
    border: 1px solid var(--border);
    border-radius: 8px;
}

.feature strong {
    display: block;
    margin-bottom: 0.5rem;
    color: var(--text);
}

.feature span {
    font-size: 0.9rem;
    color: var(--text-light);
}

/* Architecture */
.layers {
    margin-top: 2rem;
}

.layer {
    padding: 2rem;
    border: 1px solid var(--border);
    border-radius: 8px;
    margin-bottom: 1rem;
}

.layer h3 {
    font-size: 1.1rem;
    margin-bottom: 0.5rem;
}

.layer p {
    margin: 0;
    font-size: 0.9rem;
}

/* CTA */
.cta {
    text-align: center;
    padding: 2rem 0;
}

.button {
    display: inline-block;
    padding: 1rem 2rem;
    background: var(--text);
    color: var(--bg);
    text-decoration: none;
    border-radius: 8px;
    font-weight: 500;
    margin: 0.5rem;
    transition: transform 0.2s, background 0.2s;
}

.button:hover {
    transform: translateY(-2px);
    background: var(--accent);
}

.button.secondary {
    background: transparent;
    color: var(--text);
    border: 1px solid var(--border);
}

.button.secondary:hover {
    background: var(--border);
    transform: none;
}

/* Footer */
footer {
    text-align: center;
    padding: 2rem;
    border-top: 1px solid var(--border);
    color: var(--text-light);
    font-size: 0.9rem;
}

/* Responsive */
@media (max-width: 600px) {
    .hero h1 {
        font-size: 2rem;
    }

    main {
        padding: 2rem 1rem;
    }

    nav {
        flex-direction: column;
        gap: 1rem;
    }

    .nav-links a {
        margin: 0 1rem;
    }
}

